---------------------------------------- icon 初始化节点
function GolemIconNew:OnInitTrans()
    local iconInst = self._iconInst
    self._uiLvTxtTrans = CS.FindTrans(iconInst,"LvTxt")
    self._uiNumTxtTrans = CS.FindTrans(iconInst,"NumTxt")
    self._uiPosImgTrans = CS.FindTrans(iconInst,"PosImg")
    self._uiHeroIconTrans = CS.FindTrans(iconInst,"HeroIcon")
    self._uiHeroIconBgTrans = CS.FindTrans(iconInst,"HeroIconBg")
    self._uiMaskImgTrans = CS.FindTrans(iconInst,"MaskImg")
    self._uiGouTrans = CS.FindTrans(iconInst,"Gou")
    self._uiLockImgTrans = CS.FindTrans(iconInst,"LockImg")
    self._uiEmptyIconTrans = CS.FindTrans(iconInst,"EmptyIcon")
    self._uiStarTrans = CS.FindTrans(iconInst,"StarList")
    self._uiEffRootTrans = CS.FindTrans(iconInst,"EffRoot")


    self:InitStartList()
end

---------------------------------------- icon 数据初始化
function GolemIconNew:InitInfo()
    local iconPath
    local iconBgPath
    local itemColor
    local itemName

    local star = 0
    local refId = self._refId

    local showPosIcon = self._showPosIcon

    local golemDrawing
    local showEffName
    if refId and refId > 0 then
        local ref = self:GetGolemElementRef(refId)
        if ref then
            iconPath = ref.icon
            itemName = ccLngText(ref.name)

            golemDrawing = ref.golemDrawing

            local quality
            if gModelGolem then
                quality = gModelGolem:GetGolemElementQualityByRefId(refId)
                star = gModelGolem:GetGolemElementStarByRefId(refId)
            else
                quality = ref.quality
                star = ref.quality
            end

            if quality then
                local qualityRef = self:GetItemQualityRef(quality)
                if qualityRef then
                    iconBgPath = qualityRef.iconBg
                    local color = qualityRef.nameColor
                    if color then
                        itemColor = LUtil.ColorByHex(color)
                    end
                end

                if quality == 5 then
                    showEffName = "ui_fx_golem_item_light_01"
                end
            end

            if showPosIcon then
                local posRef = self:GetGolemLocationRef(golemDrawing)
                if posRef then
                    self:SetDisplayPos(posRef.icon)
                end
            end
        end
    end
    local setGolemDrawing = self._golemDrawing
    if setGolemDrawing and setGolemDrawing > 0 then
        golemDrawing = setGolemDrawing
    end
    if not iconPath and golemDrawing then
        local posRef = self:GetGolemLocationRef(golemDrawing)
        if posRef then
            iconPath = posRef.emptylcon
            if LxResPathUtil.GetSpritePath(iconPath) == nil then
                iconPath = "public_onhook_un_add"
            end
        end
    end

    iconBgPath = iconBgPath or "public_item_bg_1"

    local dataType = self._dataType
    if dataType == GolemIconNew.DATA_TYPE_COMMON then

    elseif dataType == GolemIconNew.DATA_TYPE_SET then

    end

    self._showEffName = showEffName

    self._displayStar = star
    self._displayName = itemName
    self._displayColor = itemColor
    self._displayShowIcon = iconPath
    self._displayShowIconBg = iconBgPath
end

---------------------------------------- icon 数据处理
function GolemIconNew:SetGolemData(data)
    self._dataType = GolemIconNew.DATA_TYPE_SET

    if data.refId then
        self._refId = data.refId
    end
    if data.lvlRefId then
        self._lvlRefId = data.lvlRefId
    end
    if data.lvl then
        self._lvl = data.lvl
    end
    if data.golemDrawing then
        self._golemDrawing = data.golemDrawing
    end

    self:SetDisplayPos(data.displayPos)
    self:SetDisplayHero(data.displayHero)
    self:SetDisplayHeroBg(data.displayHeroBg)

    self:SetEmptyShowStatus(data.showEmpty or false)
    self:SetMaskShowStatus(data.showMask or false)
    self:SetLockShowStatus(data.showLock or false)
    self:SetGouShowStatus(data.showGou or false)

    if data.showPosIcon ~= nil then
        self:SetPosIconShowStatus(data.showPosIcon)
    end

    self:InitInfo()
end

function GolemIconNew:SetGolemIcon(itemRefId,itemNum)
    self._dataType = GolemIconNew.DATA_TYPE_COMMON
    self._refId = itemRefId
    self._showNum = itemNum
    self:InitInfo()
end

