---------------------------------------- icon 刷新
function GolemIconNew:ApplyLvTxt()
    local show = false
    local lv = self._lvl
    if lv and lv > 0 then
        self:SetXUIText(self._uiLvTxtTrans,string.replace("+ #a1#",lv))
        show = true
    end
    if self._uiLvTxtTrans.gameObject.activeSelf ~= show then
        CS.ShowObject(self._uiLvTxtTrans, show)
    end
end

function GolemIconNew:ApplyNumTxt()
    local showNumTxt = self._showNum
    local str = showNumTxt or ""
    self:SetXUIText(self._uiNumTxtTrans,str)
end

function GolemIconNew:ApplyShowEff()
    local showEffName = self._showEffName
    local showEff = showEffName ~= nil
    if showEff then
        self:CreateIconEffect({
            trans = self._uiEffRootTrans,
            effName = showEffName,
        })
    end
    if self._uiEffRootTrans.gameObject.activeSelf ~= showEff then
        CS.ShowObject(self._uiEffRootTrans, showEff)
    end
end

function GolemIconNew:ApplyPosImg()
    local displayPos = self._displayPos
    if displayPos then
        self:SetCommonImg(self._uiPosImgTrans, displayPos,function()
            if self:IsDestroy() then return end
            if self._uiPosImgTrans and CS.IsValidObject(self._uiPosImgTrans) and not self._uiPosImgTrans.gameObject.activeSelf then
                CS.ShowObject(self._uiPosImgTrans,true)
            end
        end)
    else
        if self._uiPosImgTrans.gameObject.activeSelf then
            CS.ShowObject(self._uiPosImgTrans,false)
        end
    end
end

function GolemIconNew:ApplyHeroIcon()
    local displayHero = self._displayHero
    if displayHero then
        self:SetCommonImg(self._uiHeroIconTrans, displayHero,function()
            if self:IsDestroy() then return end
            if self._uiHeroIconTrans and CS.IsValidObject(self._uiHeroIconTrans) and not self._uiHeroIconTrans.gameObject.activeSelf then
                CS.ShowObject(self._uiHeroIconTrans,true)
            end
        end)
    else
        if self._uiHeroIconTrans.gameObject.activeSelf then
            CS.ShowObject(self._uiHeroIconTrans,false)
        end
    end
    local displayHeroBg = self._displayHeroBg
    if displayHeroBg then
        self:SetCommonImg(self._uiHeroIconBgTrans, displayHeroBg,function()
            if self:IsDestroy() then return end
            if self._uiHeroIconBgTrans and CS.IsValidObject(self._uiHeroIconBgTrans) and not self._uiHeroIconBgTrans.gameObject.activeSelf then
                CS.ShowObject(self._uiHeroIconBgTrans,true)
            end
        end)
    else
        if self._uiHeroIconBgTrans.gameObject.activeSelf then
            CS.ShowObject(self._uiHeroIconBgTrans,false)
        end
    end
end

function GolemIconNew:ApplyMaskShow()
    local show = self._showMask or self._showGou or self._showLock
    if self._uiMaskImgTrans.gameObject.activeSelf ~= show then
        CS.ShowObject(self._uiMaskImgTrans,show)
    end
end

function GolemIconNew:ApplyGouShow()
    local show = self._showGou
    if self._uiGouTrans.gameObject.activeSelf ~= show then
        CS.ShowObject(self._uiGouTrans,show)
    end
end

function GolemIconNew:ApplyLockShow()
    local show = self._showLock
    if self._uiLockImgTrans.gameObject.activeSelf ~= show then
        CS.ShowObject(self._uiLockImgTrans,show)
    end
end

function GolemIconNew:ApplyEmptyShow()
    local show = self._showEmpty
    if self._uiEmptyIconTrans.gameObject.activeSelf ~= show then
        CS.ShowObject(self._uiEmptyIconTrans,show)
    end
end

function GolemIconNew:ApplyIconUI()
    BaseIconNew.ApplyIconUI(self)

    self:SetIcon(self._displayShowIcon)
    self:SetIconBg(self._displayShowIconBg)
    self:UpdateStarUI()

    self:ApplyLvTxt()
    self:ApplyNumTxt()
    self:ApplyPosImg()
    self:ApplyShowEff()
    self:ApplyHeroIcon()

    self:ApplyMaskShow()
    self:ApplyGouShow()
    self:ApplyLockShow()
    self:ApplyEmptyShow()
end

---------------------------------------- 获取名字
function GolemIconNew:GetNameData()
    return self._displayName,self._displayColor
end

---------------------------------------- ref
function GolemIconNew:GetGolemElementRef(refId)
    return GameTable.GolemElementRef[refId]
end

function GolemIconNew:GetGolemLocationRef(refId)
    return GameTable.GolemLocationRef[refId]
end



return GolemIconNew